import{_ as t,o as i,c as a,a2 as n}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Interactive Web Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/dashboard.md","filePath":"en/guide/dashboard.md","lastUpdated":1774877157000}'),o={name:"en/guide/dashboard.md"};function s(r,e,l,d,c,g){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="interactive-web-dashboard" tabindex="-1">Interactive Web Dashboard <a class="header-anchor" href="#interactive-web-dashboard" aria-label="Permalink to &quot;Interactive Web Dashboard&quot;">​</a></h1><p><a href="https://srebot.site360.tech" target="_blank" rel="noreferrer">SREBot Web Dashboard</a> acts as your platform&#39;s primary control center. Aside from administering security options and configuration, it enables rigorous tracing of SREBot&#39;s operational logic per incident.</p><h2 id="incident-analysis-detail-view" tabindex="-1">Incident Analysis Detail View <a class="header-anchor" href="#incident-analysis-detail-view" aria-label="Permalink to &quot;Incident Analysis Detail View&quot;">​</a></h2><p>SREBot excels by exposing complete transparency (its &quot;thought process&quot;) into the LLM executions. Over on your summary view, colored severity indicators delineate priority issues.</p><p>Clicking an incident drills down into the <strong>Detailed RCA Record</strong>, showcasing:</p><ul><li><strong>Processing State:</strong> Processing state (<code>analyzing</code>), finished state (<code>completed</code>), or errored (<code>failed</code>).</li><li><strong>Written RCA Output:</strong> The finalized, comprehensive issue breakdown provided to Telegram.</li><li><strong>LLM Tool Executions (Logs):</strong> You can transparently observe the step-by-step PromQL interactions or Elasticsearch DSL requests made by SREBot.</li></ul><p>This allows analysts to sanity-test the decisions directly (averting hallucinations) while repurposing verified PromQL snippets immediately into standard Grafana charts.</p><h2 id="token-billing-system" tabindex="-1">Token Billing System <a class="header-anchor" href="#token-billing-system" aria-label="Permalink to &quot;Token Billing System&quot;">​</a></h2><p>SREBot utilizes a flexible <strong>token-based</strong> pricing foundation covering the backend LLM orchestrator costs.</p><ul><li><strong>Rates:</strong> Expenses scale per every <code>1 Million</code> tokens ingested (<code>input</code>) or returned (<code>output</code>). Base pricing relies on your organization&#39;s active <strong>Billing Tariff</strong>.</li><li><strong>Usage Allocations:</strong> Allocations deplete from your USD balance. Charges apply asynchronously after every fully finalized RCA pipeline run.</li><li><strong>Auditing Logs:</strong> Visualized billing charts present clear expenditure lines, accompanied by robust transaction logs reporting standard TopUps and granular USAGE deductions.</li><li><strong>Adding Funds:</strong> Various gateways natively orchestrate frictionless account funding—such as Robokassa logic and native Gift mechanisms.</li></ul><div class="danger custom-block"><p class="custom-block-title">Blocking Behaviors</p><p>Should your organizational account drop below <code>0.0</code>, SREBot freezes analysis requests. A designated push alert directly notifies your Telegram chat specifying the underlying balance requirement—analysis won&#39;t run.</p></div><h2 id="security-organization-settings" tabindex="-1">Security &amp; Organization Settings <a class="header-anchor" href="#security-organization-settings" aria-label="Permalink to &quot;Security &amp; Organization Settings&quot;">​</a></h2><ul><li><strong>Identity Management:</strong> Access encompasses secure JWT workflows, alongside email-driven token resets.</li><li>Role boundaries secure the organization against unexpected edits.</li></ul>',13)])])}const h=t(o,[["render",s]]);export{p as __pageData,h as default};
